26→const DIRECTIONS = {
27→  MECHANIC: [
28→    { value: 'MECHANIC', label: 'Mexanik', icon: '🔧' },
29→    { value: 'ELECTRIC', label: 'Elektrik', icon: '⚡' },
30→    { value: 'UZLAVYAZ', label: 'Uzlavyaz', icon: '🧵' },
31→  ],
