50→  const [customReason, setCustomReason] = useState('');
51→  const [showReasons, setShowReasons] = useState(false);
52→  const [forwardCall, setForwardCall] = useState(null);
53→  const prevCallsRef = useRef([]);
54→
55→  const token = localStorage.getItem('token');
56→  const headers = { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' };
57→  const API = `http://${window.location.hostname}:8000`;
58→
59→  const playAlert = (signalType) => {
60→    try {
61→      const ctx = new (window.AudioContext || window.webkitAudioContext)();
62→      const osc = ctx.createOscillator();
63→      const gain = ctx.createGain();
64→      osc.connect(gain);
65→      gain.connect(ctx.destination);
66→      gain.gain.value = 0.3;
67→      if (signalType === 'ELECTRIC') { osc.frequency.value = 660; osc.type = 'sawtooth'; }
68→      else if (signalType === 'ASNOVA') { osc.frequency.value = 440; osc.type = 'triangle'; }
69→      else { osc.frequency.value = 520; osc.type = 'sine'; }
70→      osc.start();
71→      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 1.5);
72→      osc.stop(ctx.currentTime + 1.5);
73→    } catch (e) {}
74→  };
75→
76→  const fetchCalls = async () => {
77→    try {
78→      const res = await fetch(`${API}/mechanic-calls`, { headers });
79→      if (res.ok) {
80→        const data = await res.json();
81→        const newPending = data.filter(c => c.status === 'PENDING');
82→        const oldPending = prevCallsRef.current.filter(c => c.status === 'PENDING');
83→        if (newPending.length > oldPending.length) {
84→          const newCall = newPending.find(nc => !oldPending.some(oc => oc.id === nc.id));
85→          if (newCall) playAlert(newCall.signal_type || 'MECHANIC');
86→        }
87→        prevCallsRef.current = data;
88→        setCalls(data);
89→      }
90→    } catch (e) {}
91→  };
92→
93→  useEffect(() => {
94→    fetchCalls();
95→    const i = setInterval(fetchCalls, 3000);
96→    const h = () => fetchCalls();
97→    window.addEventListener('app-refresh', h);
98→    return () => { clearInterval(i); window.removeEventListener('app-refresh', h); };
