100→
101→  const updateStatus = async (id, status) => {
102→    try {
103→      await fetch(`${API}/mechanic-calls/${id}`, {
104→        method: 'PUT', headers, body: JSON.stringify({ status })
105→      });
106→      fetchCalls();
107→      emitRefresh();
108→    } catch (e) {}
109→  };
110→
111→  const handleForward = async (callId, newSignalType) => {
