113→      await fetch(`${API}/mechanic-calls/${callId}`, {
114→        method: 'PUT', headers, body: JSON.stringify({ status: 'PENDING', signal_type: newSignalType })
115→      });
116→      setForwardCall(null);
117→      fetchCalls();
118→      emitRefresh();
119→    } catch (e) {}
120→  };
121→
122→  const handleCreateCall = async () => {
123→    if (!callForm.machine_id) return;
124→    let reason = selectedReasons.filter(r => r !== 'Boshqa').join(', ');
125→    if (customReason) reason += (reason ? ', ' : '') + customReason;
126→    if (!reason) return;
127→    try {
128→      const res = await fetch(`${API}/mechanic-calls`, {
129→        method: 'POST', headers, body: JSON.stringify({ ...callForm, reason })
130→      });
131→      if (res.ok) {
132→        setCallForm({ machine_id: '', signal_type: 'MECHANIC', direction: 'MECHANIC' });
133→        setSelectedReasons([]);
134→        setCustomReason('');
135→        setShowReasons(false);
136→        setShowCallForm(false);
137→        fetchCalls();
138→        emitRefresh();
139→      }
140→    } catch (e) {}
141→  };
142→
143→  const toggleReason = (reason) => {
144→    if (reason === 'Boshqa') {
145→      setSelectedReasons(prev => prev.includes('Boshqa') ? [] : ['Boshqa']);
146→      setCustomReason('');
147→    } else {
148→      setSelectedReasons(prev =>
149→        prev.includes(reason) ? prev.filter(r => r !== reason) : [...prev.filter(r => r !== 'Boshqa'), reason]
150→      );
151→    }
152→  };
153→
154→  const handleSignalChange = (type) => {
155→    const dirs = DIRECTIONS[type] || DIRECTIONS.MECHANIC;
156→    setCallForm({ ...callForm, signal_type: type, direction: dirs[0].value });
